import React, { useState } from "react";
import {
  FiSettings,
  FiBell,
  FiLock,
  FiUser,
  FiMoon,
  FiEdit,
  FiSave,
} from "react-icons/fi";

const Settings = () => {
  const [editing, setEditing] = useState(false);

  const [settings, setSettings] = useState({
    username: "Admin User",
    email: "admin@example.com",
    notifications: true,
    autoSave: true,
    twoFactor: true,
    darkMode: false,
    language: "English",
  });

  const handleChange = (e) => {
    const { name, value, checked, type } = e.target;

    setSettings((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleSave = () => {
    alert("Settings Updated Successfully!");
    setEditing(false);
  };

  return (
    <div className="space-y-6">

      {/* Header */}
      <div className="bg-white rounded-xl shadow border p-6 flex justify-between items-center">

        <div className="flex items-center gap-4">
          <div className="bg-purple-600 p-3 rounded-xl text-white">
            <FiSettings size={24} />
          </div>

          <div>
            <h2 className="text-2xl font-bold">Settings</h2>
            <p className="text-gray-500">
              Manage application preferences
            </p>
          </div>
        </div>

        {!editing ? (
          <button
            onClick={() => setEditing(true)}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2 rounded-lg"
          >
            <FiEdit />
            Edit
          </button>
        ) : (
          <button
            onClick={handleSave}
            className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-5 py-2 rounded-lg"
          >
            <FiSave />
            Save
          </button>
        )}

      </div>

      <div className="grid lg:grid-cols-2 gap-6">

        {/* Profile */}
        <div className="bg-white rounded-xl shadow border p-6">

          <div className="flex items-center gap-2 mb-4">
            <FiUser />
            <h3 className="font-semibold text-lg">
              Profile
            </h3>
          </div>

          <div className="space-y-4">

            <input
              name="username"
              value={settings.username}
              disabled={!editing}
              onChange={handleChange}
              className="w-full border rounded-lg px-4 py-2 disabled:bg-gray-100"
            />

            <input
              name="email"
              value={settings.email}
              disabled={!editing}
              onChange={handleChange}
              className="w-full border rounded-lg px-4 py-2 disabled:bg-gray-100"
            />

          </div>

        </div>

        {/* Notifications */}
        <div className="bg-white rounded-xl shadow border p-6">

          <div className="flex items-center gap-2 mb-4">
            <FiBell />
            <h3 className="font-semibold text-lg">
              Notifications
            </h3>
          </div>

          <label className="flex justify-between py-3">
            <span>Email Notifications</span>

            <input
              type="checkbox"
              name="notifications"
              checked={settings.notifications}
              disabled={!editing}
              onChange={handleChange}
            />
          </label>

          <label className="flex justify-between py-3">
            <span>Auto Save</span>

            <input
              type="checkbox"
              name="autoSave"
              checked={settings.autoSave}
              disabled={!editing}
              onChange={handleChange}
            />
          </label>

        </div>

        {/* Security */}
        <div className="bg-white rounded-xl shadow border p-6">

          <div className="flex items-center gap-2 mb-4">
            <FiLock />
            <h3 className="font-semibold text-lg">
              Security
            </h3>
          </div>

          <label className="flex justify-between py-3">
            <span>Two Factor Authentication</span>

            <input
              type="checkbox"
              name="twoFactor"
              checked={settings.twoFactor}
              disabled={!editing}
              onChange={handleChange}
            />
          </label>

        </div>

        {/* Appearance */}
        <div className="bg-white rounded-xl shadow border p-6">

          <div className="flex items-center gap-2 mb-4">
            <FiMoon />
            <h3 className="font-semibold text-lg">
              Appearance
            </h3>
          </div>

          <label className="flex justify-between py-3">
            <span>Dark Mode</span>

            <input
              type="checkbox"
              name="darkMode"
              checked={settings.darkMode}
              disabled={!editing}
              onChange={handleChange}
            />
          </label>

          <select
            name="language"
            value={settings.language}
            disabled={!editing}
            onChange={handleChange}
            className="w-full mt-4 border rounded-lg px-4 py-2 disabled:bg-gray-100"
          >
            <option>English</option>
            <option>Hindi</option>
            <option>Gujarati</option>
          </select>

        </div>

      </div>

    </div>
  );
};

export default Settings;
